40→      <div className={divider} />
41→      <div className={socialLinksRow}>
42→        <SocialLinks />
43→      </div>
44→    </div>
45→  );
46→};
47→
48→const HomePublished = withPublishedData(Home);
49→
50→export function HomePage() {
51→  const loaderData = Route.useLoaderData();
52→
53→  // Use the reactive preview store instead of only the loader's isPreview
54→  // This allows the component to switch when preview mode is detected client-side
55→  const { isPreview: isPreviewFromStore } = useStore(
56→    previewStore,
57→    (state) => state,
58→  );
59→
60→  const {
61→    initial,
62→    options,
63→    query,
64→    params,
65→    sanity: { isPreview: isPreviewFromLoader },
66→  } = loaderData;
67→
68→  // Use the store value (client-side reactive) with loader as fallback (SSR)
69→  const isPreview = isPreviewFromStore || isPreviewFromLoader;
70→
71→  return isPreview ? (
72→    <Suspense fallback={null}>
73→      <PreviewWrapper
74→        query={query}
75→        params={params}
76→        initial={initial}
77→        component={Home as PreviewableComponent}
78→      />
79→    </Suspense>
80→  ) : (
81→    <HomePublished initial={initial?.data} tanstackQuery={homeQuery(options)} />
82→  );
83→}
84→

 1→import {
 2→  heroContent,
 3→  heroSection,
 4→  heroSubtitle,
 5→  heroTitle,
 6→} from "../Home.css.ts";
 7→
 8→interface HeroSectionProps {
 9→  title?: string | null;
10→  subTitle?: string | null;
11→}
12→
13→export function HeroSection({ title, subTitle }: HeroSectionProps) {
14→  return (
15→    <section className={heroSection}>
16→      <div className={heroContent}>
17→        <h1 className={heroTitle}>{title}</h1>
18→        {subTitle && <p className={heroSubtitle}>{subTitle}</p>}
19→      </div>
20→    </section>
21→  );
22→}
23→

 1→import { CATEGORIES_PER_PAGE, POSTS_PER_PAGE } from '@/constants/config.ts';
 2→import { getPostsQuery } from '@/sanity/queries/postQuery.ts';
 3→import { fetchHomeData } from '@/sanity/serverFunctions.ts';
 4→import type { UnfilteredResponseQueryOptions } from '@sanity/client';
 5→import { queryOptions } from '@tanstack/react-query';
 6→import groq from 'groq';
 7→
 8→// Groq query - exported for preview mode
 9→export const HOME_QUERY = groq`{
10→  "homeData": *[_type == "home"][0]{ 
11→    title, 
12→    subTitle, 
13→    headingCard1, 
14→    headingCard2, 
15→    headingCard3, 
16→    card1, 
17→    card2, 
18→    card3 
19→  },
20→  "postsData": ${getPostsQuery(POSTS_PER_PAGE)},
21→  "categoriesData": *[_type == "category"] | order(_createdAt desc)[0..${CATEGORIES_PER_PAGE}] { title, fullSlug, mainImage, description, _createdAt }
22→}`;
23→
24→// Tanstack Query - uses server function to ensure data is fetched server-side
25→export const homeQuery = (options: UnfilteredResponseQueryOptions) =>
26→	queryOptions({
27→		queryKey: ['home', options.perspective || 'published'],
28→		staleTime: 1000 * 60 * 5, // Consider data fresh for 5 minutes
29→		gcTime: 1000 * 60 * 30, // Keep in cache for 30 minutes
30→		queryFn: () => fetchHomeData(),
31→	});
32→

1→import { blockTypes } from './blockTypes';
2→import { documentTypes } from './documentTypes';
3→import { fieldTypes } from './fieldTypes';
4→
5→export const schemaTypes = [...documentTypes, ...blockTypes, ...fieldTypes];
6→

 1→import { LoadingSpinner } from '@/components/LoadingSpinner/LoadingSpinner.tsx';
 2→import { homeLoader } from '@/loaders/home.ts';
 3→import { HomePage } from '@/pages/Home/Home.tsx';
 4→import { homeMeta } from '@/pages/Home/meta.ts';
 5→import { createFileRoute } from '@tanstack/react-router';
 6→
 7→// Index Route
 8→export const Route = createFileRoute('/')({
 9→	component: HomePage,
10→	loader: homeLoader,
11→	head: ({ loaderData, match }) => homeMeta(loaderData?.initial?.data.homeData, match.fullPath),
12→	pendingComponent: LoadingSpinner,
13→});
14→

 1→import { detectPreviewMode, validatePreviewToken } from '@/lib/previewMode';
 2→import { STUDIO_BASEPATH } from '@/sanity/constants.ts';
 3→import { HOME_QUERY, homeQuery } from '@/sanity/queries/homeQuery.ts';
 4→import type { ClientPerspective, UnfilteredResponseQueryOptions } from '@sanity/client';
 5→import type { QueryClient } from '@tanstack/react-query';
 6→
 7→export const homeLoader = async ({
 8→	context,
 9→}: {
10→	context: { queryClient: QueryClient; request: Request | null; isPreview?: boolean };
11→}) => {
12→	// Detect if preview mode is active
13→	const isPreviewMode = await detectPreviewMode(context.request);
14→	validatePreviewToken(isPreviewMode);
15→	const previewToken = import.meta.env.SSR ? process.env.SANITY_READ_TOKEN : undefined;
16→
17→	const options = {
18→		filterResponse: false,
19→		perspective: isPreviewMode ? ('drafts' as ClientPerspective) : ('published' as ClientPerspective),
20→		...(isPreviewMode && previewToken ? { token: previewToken } : {}),
21→		...(isPreviewMode ? { stega: { enabled: true, studioUrl: STUDIO_BASEPATH } } : {}),
22→	} as UnfilteredResponseQueryOptions;
23→
24→	const initial = await context.queryClient.ensureQueryData(homeQuery(options));
25→
26→	// Return options without stega to avoid type incompatibility
27→	const returnOptions = {
28→		filterResponse: false as const,
29→		perspective: options.perspective as ClientPerspective,
30→		...(options.token ? { token: options.token } : {}),
31→	};
32→
33→	return {
34→		initial,
35→		options: returnOptions,
36→		query: HOME_QUERY,
37→		params: { lastPublishedAt: null, lastId: null },
38→		sanity: { isPreview: isPreviewMode },
39→	};
40→};
