import {
  heroContent,
  heroSection,
  heroSubtitle,
  heroSubtitleEmojis,
  heroTitle,
} from "../Home.css.ts";

interface HeroSectionProps {
  title?: string | null;
  subTitle?: string | null;
}

const emojiRegex = /(\p{Emoji_Presentation}|\p{Extended_Pictographic})/gu;

/** Splits trailing emojis from the subtitle so they can be styled separately on mobile. */
function splitTrailingEmojis(text: string) {
  const trimmed = text.trimEnd();
  const match = trimmed.match(/[\s\p{Emoji_Presentation}\p{Extended_Pictographic}]+$/u);
  if (!match) return { text: trimmed, emojis: "" };
  const emojis = match[0].match(emojiRegex);
  if (!emojis) return { text: trimmed, emojis: "" };
  return {
    text: trimmed.slice(0, match.index).trimEnd(),
    emojis: emojis.join(" "),
  };
}

export function HeroSection({ title, subTitle }: HeroSectionProps) {
  const parts = subTitle ? splitTrailingEmojis(subTitle) : null;

  return (
    <section className={heroSection}>
      <div className={heroContent}>
        <h1 className={heroTitle}>{title}</h1>
        {parts && (
          <p className={heroSubtitle}>
            {parts.text}
            {parts.emojis && (
              <span className={heroSubtitleEmojis}>{parts.emojis}</span>
            )}
          </p>
        )}
      </div>
    </section>
  );
}

